  color: var(--theme-elevation-800);
}

.json-inspector__block-type {
  font-size: 0.75rem;
  font-family: monospace;
  color: var(--theme-elevation-600);
  background: var(--theme-elevation-100);
  padding: 0.125rem 0.375rem;
  border-radius: 3px;
}

.json-inspector__actions {
  display: flex;
  gap: 0.25rem;
}

.json-inspector__content {
  flex: 1;
  overflow: auto;
  padding: 1rem;
}

.json-inspector__pre {
  margin: 0;
  font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
  font-size: 0.8125rem;
  line-height: 1.6;
  color: #d4d4d4;
  white-space: pre-wrap;
  word-wrap: break-word;
  background: #1e1e1e !important;
  padding: 1rem;
  border-radius: 4px;
}

/* Preview mode syntax highlighting */
.json-inspector__pre .token.property {
  color: #9cdcfe !important;
}

.json-inspector__pre .token.string {
  color: #ce9178 !important;
}

.json-inspector__pre .token.number {
  color: #b5cea8 !important;
}

.json-inspector__pre .token.boolean,
.json-inspector__pre .token.null {
  color: #569cd6 !important;
}

.json-inspector__pre .token.punctuation {
  color: #d4d4d4 !important;
}

/* JSON Editor wrapper for syntax highlighting overlay */
.json-inspector__editor {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 400px;
  background: #1e1e1e;
}

.json-inspector__textarea {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  padding: 1rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
  font-size: 0.8125rem;
  line-height: 1.6;
  color: #d4d4d4;
  background: #1e1e1e;
  resize: none;
  caret-color: #ffffff;
  z-index: 2;
  white-space: pre;
  overflow-wrap: normal;
  word-wrap: normal;
}

.json-inspector__textarea--editable {
  position: absolute;
  top: 0;
  left: 0;
}

.json-inspector__textarea:focus {
  outline: none;
  border-color: var(--theme-elevation-400);
}

.json-inspector__pre--overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  padding: 1rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  pointer-events: none;
  z-index: 1;
  overflow: auto;
  margin: 0;
  font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
  font-size: 0.8125rem;
  line-height: 1.6;
  white-space: pre;
  background: #1e1e1e !important;
  /* Hidden since textarea is now opaque */
  display: none;
}

.json-inspector__pre--overlay *,
.json-inspector__pre--overlay code,
.json-inspector__pre--overlay div {
  background: transparent !important;
}

.json-inspector__error {
  padding: 0.75rem 1rem;
  background: var(--theme-error-50);
  border-bottom: 1px solid var(--theme-error-200);
  color: var(--theme-error-700);
  font-size: 0.875rem;
}

.json-inspector__error p {
  margin: 0;
}

.json-inspector__apply {
  color: var(--theme-success-600);
}

.json-inspector__apply:hover {
  background: var(--theme-success-50);
  color: var(--theme-success-700);
}

/* Mobile Tabs */
.editor-mobile-tabs {
  display: none;
  border-bottom: 1px solid var(--theme-elevation-200);
  margin-bottom: 1rem;
}

.editor-mobile-tab {
  flex: 1;
  padding: 0.75rem 1rem;
  border: none;
  background: transparent;
  border-bottom: 2px solid transparent;
  color: var(--theme-elevation-600);
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
}

.editor-mobile-tab:hover {
  color: var(--theme-elevation-800);
  background: var(--theme-elevation-50);
}

.editor-mobile-tab.active {
  color: var(--theme-elevation-900);
  border-bottom-color: var(--theme-elevation-900);
}

.editor-json-panel--mobile {
  width: 100% !important;
  border: none;
  border-top: 1px solid var(--theme-elevation-200);
  max-height: none;
}

/* Responsive Styles */
@media (max-width: 1023px) {
  .editor-mobile-tabs {
    display: flex;
  }

  .editor-layout {
    flex-direction: column;
  }

  .editor-splitter {
    display: none;
  }

  .editor-json-panel:not(.editor-json-panel--mobile) {
    width: 100% !important;
    border-left: none;
    border-top: 1px solid var(--theme-elevation-200);
    max-height: 50vh;
  }
}

/* Media Picker Styles */

.block-media-section {
  padding: 0.75rem 1rem;
  border-top: 1px solid var(--theme-elevation-150);
  background: var(--theme-elevation-25);
}

.block-media-button {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  background: var(--theme-elevation-0);
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  font-size: 0.875rem;
  color: var(--theme-elevation-700);
  cursor: pointer;
  transition: all 0.15s;
}

.block-media-button:hover {
  background: var(--theme-elevation-50);
  border-color: var(--theme-elevation-300);
  color: var(--theme-elevation-900);
}

.block-media-loading {
  font-size: 0.875rem;
  color: var(--theme-elevation-600);
  padding: 0.5rem 0;
}

.block-media-preview {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 0.75rem;
}

.media-thumbnail-preview {
  position: relative;
  width: 80px;
  height: 80px;
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid var(--theme-elevation-200);
  background: var(--theme-elevation-50);
}

.media-thumbnail-preview img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.media-thumbnail-remove {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  border: none;
  cursor: pointer;
  font-size: 16px;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s;
}

.media-thumbnail-remove:hover {
  background: rgba(0, 0, 0, 0.9);
}

.media-thumbnail-name {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 0.25rem;
  background: rgba(0, 0, 0, 0.7);
  color: white;
  font-size: 0.625rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Block Type Selector Modal */
.block-type-selector-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.block-type-selector-modal {
  background: var(--theme-elevation-0);
  border-radius: 8px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
  max-width: 600px;
  width: 90%;
  max-height: 80vh;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.block-type-selector-header {
  padding: 1.5rem;
  border-bottom: 1px solid var(--theme-elevation-150);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.block-type-selector-header h3 {
  margin: 0;
  font-size: 1.25rem;
  font-weight: 600;
  color: var(--theme-elevation-1000);
}

.block-type-selector-grid {
  padding: 1.5rem;
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
  overflow-y: auto;
}

.block-type-option {
  display: flex;
  align-items: flex-start;
  gap: 1rem;
  padding: 1.25rem;
  background: var(--theme-elevation-50);
  border: 2px solid var(--theme-elevation-200);
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.15s;
  text-align: left;
  width: 100%;
}

.block-type-option:hover {
  background: var(--theme-elevation-100);
  border-color: var(--theme-info-500);
}

.block-type-option-icon {
  color: var(--theme-info-500);
  flex-shrink: 0;
}

.block-type-option-content {
  flex: 1;
}

.block-type-option-label {
  font-size: 1rem;
  font-weight: 600;
  color: var(--theme-elevation-1000);
  margin-bottom: 0.25rem;
}

.block-type-option-description {
  font-size: 0.875rem;
  color: var(--theme-elevation-700);
  line-height: 1.4;
}

@media (max-width: 640px) {
  .block-type-selector-modal {
    width: 95%;
  }

  .block-type-selector-grid {
    padding: 1rem;
  }

  .block-type-option {
    padding: 1rem;
  }
}

/* Question Block Wrapper */
.question-block-wrapper {
  padding: 0.5rem 0;
}

.question-block-json-toggle {
  margin-top: 1rem;
}

/* Inline Rich Text Editor (shorter variant) */
.inline-rich-text-editor {
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  background: var(--theme-elevation-0);
}

.inline-rich-text-toolbar {
  display: flex;
  gap: 0.25rem;
  padding: 0.375rem 0.5rem;
  border-bottom: 1px solid var(--theme-elevation-150);
  background: var(--theme-elevation-50);
}

.inline-rich-text-textarea {
  width: 100%;
  min-height: 80px;
  padding: 0.75rem;
  border: none;
  font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;
  font-size: 0.875rem;
  line-height: 1.5;
  color: var(--theme-elevation-1000);
  background: transparent;
  resize: vertical;
}

.inline-rich-text-textarea:focus {
  outline: none;
}

.inline-rich-text-footer {
  padding: 0.375rem 0.75rem;
  background: var(--theme-elevation-50);
  border-top: 1px solid var(--theme-elevation-150);
  font-size: 0.75rem;
  color: var(--theme-elevation-600);
  text-align: right;
}

.inline-rich-text-media {
  padding: 0.5rem 0.75rem;
  border-top: 1px solid var(--theme-elevation-150);
  background: var(--theme-elevation-50);
}

.inline-rich-text-media-loading {
  font-size: 0.75rem;
  color: var(--theme-elevation-600);
}

.inline-rich-text-media-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.inline-rich-text-media-item {
  display: flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.25rem 0.5rem 0.25rem 0.25rem;
  background: var(--theme-elevation-0);
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  font-size: 0.75rem;
}

.inline-rich-text-media-thumb {
  width: 32px;
  height: 32px;
  border-radius: 2px;
  object-fit: cover;
  border: 1px solid var(--theme-elevation-200);
}

.inline-rich-text-media-icon {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--theme-elevation-100);
  border-radius: 2px;
  color: var(--theme-elevation-600);
}

.inline-rich-text-media-name {
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--theme-elevation-800);
}

.inline-rich-text-media-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  padding: 0;
  border: none;
  background: transparent;
  color: var(--theme-elevation-500);
  cursor: pointer;
  border-radius: 2px;
  transition: all 0.15s;
}

.inline-rich-text-media-remove:hover {
  background: var(--theme-error-100);
  color: var(--theme-error-700);
}

/* Hint & Solution Panel */
.hint-solution-panel {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.hint-solution-field {
  margin-bottom: 0.5rem;
}

.hint-solution-field-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.375rem;
}

.hint-solution-field-label {
  font-size: 0.75rem;
  font-weight: 500;
  color: var(--theme-elevation-600);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.hint-solution-field-empty {
  padding: 0.5rem 0;
}

.hint-solution-enable-btn {
  display: flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.375rem 0.75rem;
  border: 1px dashed var(--theme-elevation-300);
  border-radius: 4px;
  background: transparent;
  color: var(--theme-elevation-600);
  font-size: 0.8125rem;
  cursor: pointer;
  transition: all 0.15s;
}

.hint-solution-enable-btn:hover {
  border-color: var(--theme-info-500);
  color: var(--theme-info-500);
  background: var(--theme-info-50);
}

.hint-solution-remove-btn {
  padding: 0.25rem;
  border: none;
  background: transparent;
  color: var(--theme-elevation-500);
  border-radius: 3px;
  cursor: pointer;
  transition: all 0.15s;
}

.hint-solution-remove-btn:hover {
  background: var(--theme-error-50);
  color: var(--theme-error-500);
}

/* True/False Editor */
.true-false-editor {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.tf-option-row {
  display: flex;
  gap: 0.75rem;
}

.tf-radio-option {
  flex: 1;
  padding: 0.75rem 1rem;
  border: 2px solid var(--theme-elevation-200);
  border-radius: 6px;
  background: var(--theme-elevation-0);
  color: var(--theme-elevation-700);
  font-size: 0.9375rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.tf-radio-option:hover {
  border-color: var(--theme-elevation-300);
  background: var(--theme-elevation-50);
}

.tf-radio-option--selected {
  border-color: var(--theme-success-500);
  background: var(--theme-success-50);
  color: var(--theme-success-700);
}

.tf-radio-indicator {
  width: 18px;
  height: 18px;
  border: 2px solid var(--theme-elevation-300);
  border-radius: 50%;
  flex-shrink: 0;
  position: relative;
}

.tf-radio-option--selected .tf-radio-indicator {
  border-color: var(--theme-success-500);
}

.tf-radio-option--selected .tf-radio-indicator::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 8px;
  height: 8px;
  background: var(--theme-success-500);
  border-radius: 50%;
}

.tf-option-input {
  flex: 1;
  border: none;
  background: transparent;
  font-size: 0.9375rem;
  font-weight: 500;
  color: inherit;
  outline: none;
  min-width: 0;
  padding: 0;
}

.tf-option-input:focus {
  text-decoration: underline;
  text-underline-offset: 2px;
}

/* MCQ Editor */
.mcq-editor {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.mcq-selection-mode {
  display: flex;
  gap: 0.5rem;
}

.mcq-mode-btn {
  flex: 1;
  padding: 0.5rem 1rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  background: var(--theme-elevation-0);
  color: var(--theme-elevation-700);
  font-size: 0.8125rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
}

.mcq-mode-btn:hover {
  background: var(--theme-elevation-50);
}

.mcq-mode-btn--selected {
  border-color: var(--theme-info-500);
  background: var(--theme-info-50);
  color: var(--theme-info-700);
}

.mcq-options-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.mcq-option-row {
  display: flex;
  align-items: flex-start;
  gap: 0.75rem;
  padding: 0.75rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 6px;
  background: var(--theme-elevation-0);
}

.mcq-option-correct {
  flex-shrink: 0;
  padding-top: 0.25rem;
}

.mcq-correct-marker {
  width: 20px;
  height: 20px;
  border: 2px solid var(--theme-elevation-300);
  border-radius: 50%;
  background: var(--theme-elevation-0);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
}

.mcq-correct-marker:hover {
  border-color: var(--theme-success-400);
}

.mcq-correct-marker--checked {
  border-color: var(--theme-success-500);
  background: var(--theme-success-500);
}

.mcq-correct-inner {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: white;
}

.mcq-option-content {
  flex: 1;
  min-width: 0;
}

.mcq-option-actions {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.mcq-option-action-btn {
  padding: 0.375rem;
  border: none;
  background: transparent;
  border-radius: 3px;
  color: var(--theme-elevation-500);
  cursor: pointer;
  transition: all 0.15s;
}

.mcq-option-action-btn:hover:not(:disabled) {
  background: var(--theme-elevation-100);
  color: var(--theme-elevation-700);
}

.mcq-option-action-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.mcq-option-action-btn--delete:hover:not(:disabled) {
  background: var(--theme-error-50);
  color: var(--theme-error-500);
}

.mcq-add-option-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.625rem 1rem;
  border: 1px dashed var(--theme-elevation-300);
  border-radius: 6px;
  background: transparent;
  color: var(--theme-elevation-600);
  font-size: 0.8125rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
  margin-top: 0.5rem;
}

.mcq-add-option-btn:hover {
  border-color: var(--theme-info-500);
  color: var(--theme-info-500);
  background: var(--theme-info-50);
}

/* Free Response Editor */
.free-response-editor {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.accepted-answers-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.accepted-answer-row {
  display: flex;
  gap: 0.5rem;
}

.accepted-answer-input {
  flex: 1;
  padding: 0.625rem 0.875rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  font-size: 0.875rem;
  background: var(--theme-elevation-0);
  color: var(--theme-elevation-1000);
}

.accepted-answer-input:focus {
  outline: none;
  border-color: var(--theme-elevation-400);
}

.accepted-answer-remove-btn {
  padding: 0.5rem;
  border: 1px solid var(--theme-elevation-200);
  border-radius: 4px;
  background: var(--theme-elevation-0);
  color: var(--theme-elevation-500);
  cursor: pointer;
  transition: all 0.15s;
}

.accepted-answer-remove-btn:hover:not(:disabled) {
  background: var(--theme-error-50);
  border-color: var(--theme-error-200);
  color: var(--theme-error-500);
}

.accepted-answer-remove-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.accepted-answer-add-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.625rem 1rem;
  border: 1px dashed var(--theme-elevation-300);
  border-radius: 6px;
  background: transparent;
  color: var(--theme-elevation-600);
  font-size: 0.8125rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s;
  margin-top: 0.5rem;
}

.accepted-answer-add-btn:hover {
  border-color: var(--theme-info-500);
  color: var(--theme-info-500);
  background: var(--theme-info-50);
}

/* Shared Question Editor Styles */
.question-editor-section {
  margin-bottom: 0.5rem;
}

.question-editor-label {
  display: block;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--theme-elevation-600);
  margin-bottom: 0.5rem;
}

/* HTML Block Editor */
.html-block-editor {
  border: 1px solid var(--theme-elevation-150);
  border-radius: 4px;
  overflow: hidden;
}

.html-block-editor-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.5rem 0.75rem;
  background: var(--theme-elevation-50);
  border-bottom: 1px solid var(--theme-elevation-150);
}

.html-block-editor-label {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--theme-elevation-500);
}

.html-editor-source-toggle {
  padding: 0.25rem 0.5rem;
  font-size: 0.75rem;
  background: var(--theme-elevation-100);
  border: 1px solid var(--theme-elevation-200);
  border-radius: 3px;
  cursor: pointer;
}

.html-editor-source-toggle--active {
  background: var(--theme-elevation-200);
}

.html-block-source-textarea {
  width: 100%;
  min-height: 200px;
  padding: 1rem;
  font-family: monospace;
  font-size: 0.875rem;
  border: none;
