      expect(screen.getByText(/no graph content is visible/i)).toBeInTheDocument()
    })

    it('does not display warning when graphs are visible', () => {
      const spec = createMockSpec({
        viewportMode: 'manual',
        viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
        elements: {
          points: [],
          graphs: [{ id: 'g1', fn: 'x^2', style: 'solid', thickness: 2 }],
        },
      })
      const onChange = vi.fn()

      render(<AxisConfigPanel spec={spec} onChange={onChange} />)

      expect(screen.queryByText(/no graph content is visible/i)).not.toBeInTheDocument()
    })
  })

  // FR-003: Input value changes
  describe('onChange calls with correct values', () => {
    it('calls onChange with correct viewport values when inputs change', () => {
      const spec = createMockSpec({
        viewportMode: 'manual',
        viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
      })
      const onChange = vi.fn()

      render(<AxisConfigPanel spec={spec} onChange={onChange} />)

      const xMinInput = screen.getByLabelText(/x min/i)
